I was following a tutorial to write my consumer and producer. This is the code with modification to print time-
**Producer -**
from confluent_kafka import Producer

def acked(err, msg):
    if err is not None:
        print("Failed to deliver message: {0}: {1}"
              .format(msg.value(), err.str()))
    else:
        print("Message produced: {0}".format(msg.value()))

p = Producer({'bootstrap.servers': 'localhost:9092'})
start_time = time.time()
try:
	for val in xrange(1, 10000):
		p.produce('newtwo5', 'myvalue #{0}'.format(val))#, callback=acked)
		p.poll(0.5)
except KeyboardInterrupt:
    pass

timing=time.time()-start_time
print("Processed 10000 messsages in {0:.2f} seconds".format( timing))

p.flush(30)

**Consumer**
from confluent_kafka import Consumer, KafkaError

settings = {
    'bootstrap.servers': 'localhost:9092',
    'group.id': 'mygroup',
    'client.id': 'client-1',
    'enable.auto.commit': True,
    'session.timeout.ms': 6000,
    'default.topic.config': {'auto.offset.reset': 'smallest'}
}

c = Consumer(settings)

c.subscribe(['newtwo5'])
start_time = time.time()
try:
	while True:
		msg = c.poll(0.1)
		if msg is None:continue
		elif not msg.error():
			pass
			#print('Received message: {0}'.format(msg.value()))
		elif msg.error().code() == KafkaError._PARTITION_EOF:
			timing=time.time()-start_time
			print('End of partition reached {0}/{1} time = {2:.2f} seconds'.format(msg.topic(), msg.partition(),timing))
		else:
			print('Error occured: {0}'.format(msg.error().str()))

except KeyboardInterrupt:
    pass

finally:
    c.close()

